INSERT INTO TBL_STAT_TASK(TASK_NAME,SRC_TABLE,DEST_TABLE) VALUES('Host net flow report job','TBL_HOST_NIC_FLOW','TBL_HOST_NIC_FLOW_HOUR_STAT');
INSERT INTO TBL_STAT_TASK(TASK_NAME,SRC_TABLE,DEST_TABLE) VALUES('Host disk rate report job','TBL_HOST_IO_STAT','TBL_HOST_IO_HOUR_STAT');
INSERT INTO TBL_STAT_TASK(TASK_NAME,SRC_TABLE,DEST_TABLE) VALUES('Host disk partition rate report job','TBL_HOST_PARTITION_DETAIL_STAT','TBL_HOST_PARTITION_DETAIL_HOUR_STAT');
INSERT INTO TBL_STAT_TASK(TASK_NAME,SRC_TABLE,DEST_TABLE) VALUES('Domain disk partition rate report job','TBL_DOMAIN_PARTITION_DETAIL_STAT','TBL_DOMAIN_PARTITION_DETAIL_HOUR_STAT');
INSERT INTO TBL_STAT_TASK(TASK_NAME,SRC_TABLE,DEST_TABLE) VALUES('Domain flow link report job', 'TBL_DOMAIN_FLOW_LINK_STAT','TBL_DOMAIN_FLOW_LINK_HOUR_STAT');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (1,3,4,0,'vNIC error. Possible reasons: 1. The interface cable is incorrectly connected. 2. The interface on the remote device is down. 3. The interface is shut down by the user. 4. The interface is damaged.', 'Verify that the virtual switch and the adjacency switch are correctly configured or contact the administrator.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (2,1,4,58,'Host state error. Possible reasons: 1. The host is powered off. 2. The host is shut down. 3. The network connection is incorrect. 4. The password of the host is modified. ','1. Verify that the host is powered on. 2. Verify that the host has been started. 3. Verify that the network connection is correct. 4. Verify that the host password is correct.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (3,6,6,61,'Virtualization management software error. Possible reasons: 1. The host is disconnected. 2. The Libvert service is not running','1. Verify that the host is correctly connected. 2. Verify that the Libvert service is in running state.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (4,2,4,0,'Attached storage error. Possible reasons: 1. The storage host is powered off. 2. The storage host is shut down. 3. The network connection is incorrect.','1. Verify that the storage host is powered on. 2. Verify that the storage host has been started. 3. Verify that the network connection is correct.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (5,20,1,1,'Host CPU utilization has exceeded the threshold. Possible reasons: 1. The host is processing too many processes. 2. The host is processing a large process. 3. Too many running VMs.','1. Find out the high CPU-consumption processes by using the TOP command. 2. Verify that dynamic resource scheduling is enabled. 3. Migrate the VMs to other hosts.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6,21,1,2,'Host memory utilization has exceeded the threshold. Possible reasons: 1. The host is processing too many processes. 2. Too many running VMs.','1. Find out the high CPU-consumption processes by using the TOP command. 2. Verify that dynamic resource scheduling is enabled. 3. Migrate the VMs to other hosts.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (7,22,1,3,'Host disk utilization has exceeded the threshold. Possible reasons:1. The host disk has too many storage files. 2. Large files exist in the host storage.','1. Check the host storage files and clear useless files. 2. Verify that dynamic resource scheduling is enabled. 3. Migrate the VMs to other hosts.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8,30,2,4,'VM CPU usage exceeded the upper limit. Possible causes: 1. Too many processes are running on the VM. 2. The VM is busy with processing resource-consuming tasks. 3. The physical host on which the VM resides uses the swap partition.','1. Use the TOP command to locate CPU-consuming processes on Linux. 2. Use Resource Monitor to locate CPU-consuming processes on Windows.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (9,30,2,5,'VM memory usage exceeded the upper limit. Possible causes: 1.Too many processes are running on the VM. 2.The VM is busy with processing resource-consuming tasks.','1.Use the TOP command to locate memory-consuming processes on Linux. 2.Use Resource Monitor to locate memory-consuming processes on Windows.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (10,30,2,6,'VM disk usage exceeded the upper limit. Possible causes: 1. The VM has too many storage files. 2. Large files exist in the VM storage.','1. Check the system disk files and clear useless files. 2. Increase the storage size.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (11,40,6,9,'HA failover failed. Possible causes: 1.The cluster contains too many abnormal hosts. 2.The cluster has storage faults. 3.The cluster has network communication faults.','1.Locate the cause of the host failures. 2.Locate the cause of the storage faults. 3.Locate the cause of the network communication faults.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (12,40,3,7,'Cluster CPU usage exceeded the upper limit. Possible causes:1. Too many VMs reside on the hosts in the cluster. 2. Too many processes are running on the hosts in the cluster. 3. VMs on the hosts in the cluster are performing heavy processing.','1.Use the TOP command to locate CPU-consuming processes. 2.Manually move some VMs to other clusters.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (13,40,3,8,'Cluster memory usage exceeded the upper limit. Possible causes:1.Too many VMs reside on the hosts in the cluster. 2.Too many processes are running on the hosts in the cluster.','1. Check memory-intensive processes. 2.Manually move some VMs to other clusters.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (14,40,6,10,'Heartbeat of the host is interrupted. Possible causes: 1.The host has failed. 2.The host has network communication faults.','1.Locate the cause of the host failure. 2.Locate the cause of the network communication faults.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (15,30,4,11,'The VM failed. Possible causes: 1.VM bluescreen. 2.VM application failure. 3.The VM has OS faults.','1.Locate the cause of the hardware faults. 2.Locate the cause of the OS faults.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (16,51,6,12,'Management platform is abnormal. Possible causes: 1. The management platform failover service is running. 2. The original active management platform is abnormal.','1. Verify that the management platform failover service is running, and make sure the system is running on the active management platform. 2. Locate the cause of the failure on the original active management platform, or check for network faults.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (17,20,4,13,'Host NIC failure. Possible causes: 1.The network has link faults. 2.The host NIC has faults.','1.Locate the cause of the network link faults. 2.Locate the cause of the host NIC faults.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (18,20,4,14,'Host local disk failure. Possible causes: 1.The disk is removed from the host. 2.The disk of the host has faults.','1.Verify that the disk is present. 2.Locate the cause of the disk faults.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (19,51,6,15,'Management platform license expiration alarm. Possible cause: The management platform license will expire.','Apply for a new license.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (20,30,4,16,'VM application failure. Possible causes: 1.The port of the application is already in use. 2.The application is terminated abnormally.','1.Verify that the port of the application is not used by other applications. 2.Restart the application.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (21,30,4,0,'VM application failure cannot be recovered. Possible causes: 1.No installation files are found. 2.The application is not installed on the VM.','Verify that the application has been installed on the VM, and make sure the installing files exist.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (22,30,4,0,'Unknown error on VM applications. Possible causes: 1. The VM is not installed with the tools. 2. The tools version is too low. 3. The tools is not running.','Identify whether the tools is installed and running correctly with a correct version.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (23,30,4,19,'VM failure migration alarm. Possible causes: 1. Host failure. 2. Failure of the shared storage pool where the VM image file is located. 3. The VM was stuck or shut down. 4. VM OS blue screen.','1. Identify whether the host has hardware failure and whether the host was shut down or powered off unexpectedly. 2. Identify whether the shared storage pool which the VM is attached is operating correctly, whether can be accessed, and whether the storage link is normal. 3. Identify whether the VM is operating correctly, whether it was shut down unexpectedly, or whether the related processes were killed. 4. Identify whether the VM has blue screen.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (24,20,4,20,'Shared file system failure alarm. Possible causes: 1. The physical link between physical host and the storage device is unstable. 2. The I/O load of the physical host or the storage device is heavy. 3. Incorrect configurations on the adjacent switch cause link flapping or transmission delay. 4. The storage device is abnormal.' ,'1. Check the physical link between the physical host and the storage device and evaluate the quality of the physical link based on information obtained from the adjacent switch, such as the CRC error packet count and optical power. 2. Check the I/O delay and load of the physical host and the storage device to identify whether you need to reduce the I/O load or add I/O devices. 3. Verify that the VLAN or FC zone division is correct on the adjacent switch. 4. Check the alarm records and logs on the storage device to verify that the storage device is providing services correctly.') ; 
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (25,20,6,21,'Incorrect host time alarm. Possible causes: 1. The clock of the physical host is incorrect. 2. The clock of the management platform is incorrect. 3. The cluster has network communication faults.','1. Verify that the clock of the physical host is correct. 2. Verify that the clock of the management platform is correct. 3. Verify that the network of the cluster is operating correctly.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (26,40,6,22,'HA resource reservation alarm. Possible causes: 1.The CPU usage and memory usage of the hosts in the cluster are too high. 2.The hosts in the cluster are performing heavy processing. 3.Too many VMs are running on the cluster.','1.Check CPU-intensive and memory-intensive processes. 2.Manually move some VMs to other clusters. 3.Modify the HA resource reservation setting.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (27,20,4,23,'Virtual switch failure. Possible causes: 1. Network link failure. 2. Physical NIC bound to the virtual switch is abnormal. 3. Incorrect link aggregation configuration. 4.Failed to access the gateway.' ,'1. Locate the cause of network link failure. 2. Locate the cause of NIC abnormality. 3. Verify that link aggregation is correctly configured and the status of aggregate interfaces is correct.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (28,20,6,24,'Host clock source alarm. Possible causes: 1.The clock source of the host is not TSC. 2.The hardware of the host does not support TSC.','1. Identify whether TSC exists in the available clock source. If it exists, switch to the TSC. 2.Identify whether TSC instability exists in the system boot logs.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (29,20,1,25,'Host disk throughput alarm. Possible causes: 1. IO read and write throughput of the host disk has exceeded the threshold. 2.A process performs IO read and write frequently. 3.A lot of running VMs exist and a lot of IO read and write operations exist.','1.Use iotop/iostat to check the IO read and write status of processes. 2.Stop the IO operation of some processes to reduce the system load.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (30,30,2,26,'VM disk throughput alarm. Possible causes: 1.IO read and write throughput of the VM disk has exceeded the threshold. 2.A process performs IO read and write frequently. 3.VMs are running with high load.','1. For Windows operating systems, check the process IO information through the resource monitor. For Linux operating systems, check the process IO information through iotop/iostat. 2.Stop the IO operation of some processes to reduce the system load.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (31,20,1,27,'Host network throughput alarm. Possible causes: 1.The received and sent traffic on the Ethernet ports of the host has exceeded the threshold. 2.Some applications on the host occupy the NIC traffic. 3.A switch sends a large number of packets to the host.','1.Capture packets to identify whether some applications occupy NIC traffic. 2.Identify whether broadcast storms exist on the switch. 3.Check network connectivity and loop.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (32,30,2,28,'VM network throughput alarm. Possible causes: 1. The received and sent traffic on the Ethernet ports of the VM has exceeded the threshold. 2. Some applications on the VM occupy the NIC traffic. 3. A switch sends a large number of packets to the host where the VM resides.','1. Capture packets to identify whether some applications occupy NIC traffic. 2. Identify whether broadcast storms exist on the switch. 3. Check network connectivity and loop.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (33,51,4,29,'HA backup management platform failure alarm. Possible causes: 1. Backup platform error. 2. Backup platform network error.','1. Verify the running status of the backup management platform. 2. Identify the error reason for the network between the primary and backup platforms.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (34,20,1,32,'Host inbound network throughput exceeded the limit. Possible causes: 1. Incoming traffic on Ethernet interfaces of the host exceeds the upper limit. 2. The connected switch sends a large amount of traffic to the host.','1. Check the switch for broadcast storms. 2. Check network connections for loops.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (35,20,1,33,'Host outbound network throughput exceeded the limit. Possible causes: 1. Outgoing traffic on Ethernet interfaces of the host exceeds the upper limit. 2. Some applications generate a large amount of traffic on the NIC.','Capture packets to identify whether traffic-intensive applications exist.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (36,20,1,30,'Host disk read throughput exceeded the limit. Possible causes: 1. Some processes frequently perform read I/O operations. 2. A large number of VMs are running on the host and frequently perform read I/O operations.','1. Use the iotop and iostat commands to view read I/O statistics about processes. 2. Reduce system load by stopping I/O operations of some processes.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (37,20,1,31,'Host disk write throughput exceeded the limit. Possible causes: 1. Some processes frequently perform write I/O operations. 2. A large number of VMs are running on the host and frequently perform write I/O operations.','1. Use the iotop and iostat commands to view write I/O statistics about processes. 2. Reduce system load by stopping I/O operations of some processes.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (38,20,1,34,'Host disk total IOPS exceeded the limit. Possible causes: 1. Some processes frequently send read and write I/O requests. 2. A large number of VMs are running on the host and frequently send read and write I/O requests.','1. Use the iotop and iostat commands to view I/O statistics about processes. 2. Reduce system load by stopping I/O operations of some processes.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (39,20,1,35,'Host disk read IOPS exceeded the limit. Possible causes: 1. Some processes frequently send read I/O requests. 2. A large number of VMs are running on the host and frequently send read I/O requests.',' 1. Use the iotop and iostat commands to view read I/O statistics about processes. 2. Reduce system load by stopping I/O operations of some processes.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (40,20,1,36,'Host disk write IOPS exceeded the limit. Possible causes: 1. Some processes frequently send write I/O requests. 2. A large number of VMs are running on the host and frequently send write I/O requests.','1. Use the iotop and iostat commands to view write I/O statistics about processes. 2. Reduce system load by stopping I/O operations of some processes.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (41,20,1,37,'Host disk total I/O delay exceeded the limit. Possible causes: 1. The system is overloaded with read and write I/O requests. 2. Storage failure occurs.','1. Use the iotop and iostat commands to view I/O statistics about processes, and reduce system load by stopping I/O operations of some processes. 2. Verify that the storage of the host is running correctly, and that the storage network does not have connectivity issues.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (42,20,1,38,'Host disk read I/O delay exceeded the limit. Possible causes: 1. The system is overloaded with read I/O requests. 2. Storage failure occurs.','1. Use the iotop and iostat commands to view read I/O statistics about processes, and reduce system load by stopping I/O operations of some processes. 2. Verify that the storage of the host is running correctly, and that the storage network does not have connectivity issues.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (43,20,1,39,'Host disk write I/O delay exceeded the limit. Possible causes: 1. The system is overloaded with write I/O requests. 2. Storage failure occurs.','1. Use the iotop and iostat commands to view write I/O statistics about processes, and reduce system load by stopping I/O operations of some processes. 2. Verify that the storage of the host is running correctly, and that the storage network does not have connectivity issues.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (44,30,2,42,'VM inbound network throughput exceeded the limit. Possible causes: 1. Incoming traffic on Ethernet interfaces of the VM exceeds the upper limit. 2. Incoming traffic from the connected vSwitch exceeds the upper limit.',' 1. Check the virtual switch and the VM for broadcast storms. 2. Check network connections for loops.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (45,30,2,43,'VM outbound network throughput exceeded the limit. Possible causes: 1. Outgoing traffic on Ethernet interfaces of the VM exceeds the upper limit. 2. Some applications generate a large amount of traffic on the NIC.','Capture packets to identify whether traffic-intensive applications exist.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (46,30,2,40,'VM disk read throughput exceeded the limit. Possible causes: 1. Some processes frequently perform read I/O operations. 2. The VM is running under heavy load.','1. Use the iotop and iostat commands to view read I/O statistics about processes on a Linux VM. Use the task manager to view read I/O statistics about processes on a Windows VM. 2. Reduce system load by stopping I/O operations of some processes. ');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (47,30,2,41,'VM disk write throughput exceeded the limit. Possible causes: 1. Some processes frequently perform write I/O operations. 2. The VM is running under heavy load.','1. Use the iotop and iostat commands to view write I/O statistics about processes on a Linux VM. Use the task manager to view write I/O statistics about processes on a Windows VM. 2. Reduce system load by stopping I/O operations of some processes. ');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (48,30,2,44,'VM disk total IOPS exceeded the limit. Possible causes: 1. Some processes frequently send read and write I/O requests. 2. The VM is running under heavy load.','1. Use the iotop and iostat commands to view I/O statistics about processes on a Linux VM. Use the task manager to view I/O statistics about processes on a Windows VM. 2. Reduce system load by stopping I/O operations of some processes.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (49,30,2,45,'VM disk read IOPS exceeded the limit. Possible causes: 1. Some processes frequently send read I/O requests. 2. The VM is running under heavy load.','1. Use the iotop and iostat commands to view read I/O statistics about processes on a Linux VM. Use the task manager to view read I/O statistics about processes on a Windows VM. 2. Reduce system load by stopping I/O operations of some processes.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (50,30,2,46,'VM disk write IOPS exceeded the limit. Possible causes: 1. Some processes frequently send write I/O requests. 2. The VM is running under heavy load.','1. Use the iotop and iostat commands to view write I/O statistics about processes on a Linux VM. Use the task manager to view write I/O statistics about processes on a Windows VM. 2. Reduce system load by stopping I/O operations of some processes.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (51,30,2,47,'VM disk total I/O delay exceeded the limit. Possible causes: The system is overloaded with read and write I/O requests.','1. Use the iotop and iostat commands to view I/O statistics about processes on a Linux VM. Use the task manager to view I/O statistics about processes on a Windows VM. 2. Reduce system load by stopping I/O operations of some processes. 3. Verify that the storage that hosts the VM''s disk is running correctly.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (52,30,2,48,'VM disk read I/O delay exceeded the limit. Possible causes: The system is overloaded with read I/O requests.','1. Use the iotop and iostat commands to view read I/O statistics about processes on a Linux VM. Use the task manager to view read I/O statistics about processes on a Windows VM. 2. Reduce system load by stopping I/O operations of some processes. 3. Verify that the storage that hosts the VM''s disk is running correctly.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (53,30,2,49,'VM disk write I/O delay exceeded the limit. Possible causes: The system is overloaded with write I/O requests.','1. Use the iotop and iostat commands to view write I/O statistics about processes on a Linux VM. Use the task manager to view write I/O statistics about processes on a Windows VM. 2. Reduce system load by stopping I/O operations of some processes. 3. Verify that the storage that hosts the VM''s disk is running correctly.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (54,40,3,50,'Cluster shared storage usage exceeded the limit. Possible causes: 1. The shared storage is being used by too many VMs. 2. Too much space has been assigned to disks of the VMs that use the shared storage. 3. Too many backups exist on the shared storage.','1. Migrate some VMs to other storages. 2. Modify the backup path.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (55,40,3,51,'Cluster shared storage total throughput exceeded the limit. Possible causes: 1. Some processes of the hosts that load the shared storage frequently perform I/O operations. 2. A large number of VMs are using the shared storage and frequently perform I/O operations.','1. Use the iotop and iostat commands to view I/O statistics about processes. 2. Reduce system load by stopping I/O operations of some processes.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (56,40,3,52,'Cluster shared storage read throughput exceeded the limit. Possible causes: 1. Some processes of the hosts that load the shared storage frequently perform read I/O operations. 2. A large number of VMs are using the shared storage and frequently perform read I/O operations.','1. Use the iotop and iostat commands to view read I/O statistics about processes. 2. Reduce system load by stopping I/O operations of some processes.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (57,40,3,53,'Cluster shared storage write throughput exceeded the limit. Possible causes: 1. Some processes of the hosts that load the shared storage frequently perform write I/O operations. 2. A large number of VMs are using the shared storage and frequently perform write I/O operations.','1. Use the iotop and iostat commands to view write I/O statistics about processes. 2. Reduce system load by stopping I/O operations of some processes.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (58,40,3,54,'Cluster shared storage total IOPS exceeded the limit. Possible causes: 1. Some processes of the hosts that load the shared storage frequently send read and write I/O requests. 2. A large number of VMs are using the shared storage and send I/O requests frequently.','1. Use the iotop and iostat commands to view I/O statistics about processes. 2. Reduce system load by stopping I/O operations of some processes.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (59,40,3,55,'Cluster shared storage read IOPS exceeded the limit. Possible causes: 1. Some processes of the hosts that load the shared storage frequently send read I/O requests. 2. A large number of VMs are using the shared storage and send read I/O requests frequently.','1. Use the iotop and iostat commands to view read I/O statistics about processes. 2. Reduce system load by stopping I/O operations of some processes.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (60,40,3,56,'Cluster shared storage write IOPS exceeded the limit. Possible causes: 1. Some processes of the hosts that load the shared storage frequently send write I/O requests. 2. A large number of VMs are using the shared storage and frequently send write I/O requests.','1. Use the iotop and iostat commands to view write I/O statistics about processes. 2. Reduce system load by stopping I/O operations of some processes.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (61,20,4,57,'Host FC link failure. Possible causes: 1. HBA card failure. 2. Failure of the link between the FC storage and the host. 3. FC storage failure.','1. Troubleshoot the HBA card failure. 2. Troubleshoot the link failure. 3. Replace the FC storage.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (62,20,6,60,'Host redundant uplink failure. Possible causes: 1. Only one available link exists in the link aggregation group. 2. No available link exists in the link aggregation group.','1. Verify that the NIC of the aggregate link is operating correctly. 2. Verify that the connected switch is operating correctly. 3. Verify that the aggregate link is connected and configured correctly.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (63,30,6,62,'VM recycle bin alarm. Possible causes: The VM in the recycle bin will be deleted completely in seven days or less.','Restore the VM if you want to retrieve it. Ignore the alarm if the VM is no longer needed.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (64,30,6,63,'Automatic backup failure. Possible causes: 1. The system fails to perform backup policy-based backup automatically. 2. The backup time has passed the execution end time defined in the backup policy.','1. Verify that the storage space is sufficient. 2. Verify that the storage is operating correctly. 3. Verify that the backup time has passed the execution end time defined in the backup policy.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (65,20,6,59,'Host iSCSI/FC shared storage pool uni-path alarm. Possible causes: When the system is upgraded to E0218 or later, the path attribute for the iSCSI/FC shared storage pool is not manually modified to multi-path.','Manually remove the storage pool and re-add it.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (66,50,4,64,'Template pool fault alarm. Possible causes: 1. An exception exists on the storage. 2. An exception exists in the link between the management platform and the storage. ','1. Check whether the storage is normal. 2. Check whether the link between the management platform and the storage is normal.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (67,20,6,65,'The host enters maintenance mode. Possible causes: 1. The physical host is synchronizing data from the management platform, and the physical host is in maintenance mode.' ,'1. Wait for the management platform and the physical host to finish data synchronization. The physical host exits maintenance mode 10 minutes after the data synchronization starts.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (68,20,6,66,'A process on the host is abnormal. Possible causes: 1. A segmentation fault occurs when the process is running. 2. An assert condition is met when the process is running.' ,'1. Abnormal libvirtd process alarm. Please verify that the Libvirt service is running and the host connection is correct. 2. Abnormal kvm process alarm. Please identify whether VMs are shutdown because of failure. 3. Abnormal ovs-vswitchd process alarm. Please verify that the Openvswitch service is running and the VM network is operating correctly. 4. Abnormal cvk_ha or cvm_ha process alarm. Please verify that the HA service is running correctly. 5. Abnormal corosync process alarm. Please verify that the active/standby system is operating correctly. 6. Abnormal multipathd or iscsid process alarm. Please verify that the shared storage is operating correctly and check host reboot records.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (69,20,6,67,'Host port speed autonegotiation failure. Possible causes: 1. Negotiation between the NIC and the peer switch has failed. 2. Result of the negotiation between the NIC and the peer switch is half duplex.' ,'1. Verify that the cable to the peer switch is installed correctly. 2. Verify that the peer switch is correctly configured.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (70,20,6,68,'Host log partition size exceeded the limit. Possible causes: 1.Logs increase too fast within a specific time period.' ,'1.Identify the cause for log growth and remove it. 2.Export logs.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (71,20,6,69,'The host''s CPU temperature exceeded the limit. Possible causes: 1.The equipment room temperature is too high or the host overheats. 2.Too many processes are started on the host. 3.The host is processing large tasks. 4.Too many VMs are running on the host.' ,'1.Check the equipment room temperature and the heat dissipation system of the host. 2.Use the top command to locate CPU-consuming processes. 3.Verify that DRS is enabled. 4.Migrate some VMs from the host to other hosts.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (72,20,1,70,'Incoming packet loss rate of the host exceeded the limit. Possible causes: 1.Incoming traffic exceeded the limit on the Ethernet interface of the host. 2.The switch sent a large amount of traffic to the host. 3.Network policies or firewalls exist. 4.Loose or aging network cable.' ,'1.Check the switch for broadcast storms. 2.Verify that the network cables do not have connectivity issues, the optical power of optical cables is correct, and no loops exist in the network. 3.Verify that no network policies or firewalls exist.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (73,20,1,71,'Outgoing packet loss rate of the host exceeded the limit. Possible causes: 1.Connectivity issues on the outbound direction of the network interface. 2.Outgoing traffic exceeded the limit on the Ethernet interface of the host. 3.Some applications on the host occupy the NIC. 4.Network policies or firewalls exist. 5.Loose or aging network cable.' ,'1.Verify that the network cables do not have connectivity issues and the optical power of optical cables is correct. 2.Capture packets to identify the applications that occupy the NIC. 3.Verify that no network policies or firewalls exist.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (74,50,6,72,'Management platform automatic backup failure. Possible causes: 1. Insufficient storage. 2. Database backup failure.','1. Verify that the storage is enough. 2. Verify that the database is operating correctly.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (75,60,7,73,'Number of login failures exceeded the limit. Possible causes: 1.Login name or password failures exceeded the limit. 2.The account was locked for consecutive login failures when the operator logged in. 3.The number of logins that do not comply with the access policy exceeded the limit.' ,'Make sure the operator uses a correct login name and password for login.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (76,60,7,74,'The IP address of the operator is not permitted. Possible causes: 1.The operator logged in to the system from a host that is not permitted by the system. 2.The IP address is denied by the access policy for the operator.' ,'Make sure the access policy for the operator is correct and the operator logs in from a permitted host.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (77,60,7,75,'The operator logged in during the time period when login is denied. Possible causes: 1. The access policy for the operator limits the time period when login can be performed. 2. The management platform system time is inconsistent with the host''s local time.' ,'Make sure the access policy for the operator is correct and the management platform system time is consistent with the host''s local time.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (78,51,6,76,'Failover system split-brain alarm. Possible cause: Network between the primary and backup management platforms has faults.' ,'Please contact H3C Support.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (79,30,4,77,'VM recovery failure. Possible cause: The VM cannot resume operation on the destination host after migration.','1.Verify that the hosts in the cluster have enough CPU and memory resources for the VM to resume operation. 2.Identify whether specific settings of the VM cause the failover failure.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (80,30,4,78,'VM I/O error alarm. Possible causes: 1. VM storage network failure. 2. Storage failure.','1. Identify storage network link failure reason. 2. Identify storage server failure reason.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (81,40,4,80,'The shared file system was damaged. Possible causes: 1. It was assigned to a host not managed by CVM. 2. The disk array was damaged. 3. The shared file system was initialized or formatted.','1. Please contact the O&M or management personnel.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (82,30,2,81,'Number of received packets dropped by a VM exceeded the threshold. Possible causes: 1. Traffic received by the Ethernet port of the VM exceeded the threshold. 2. A large number of packets were sent to the VM. 3. The VM has a port profile or virtual firewall configured.','1. Verify that no broadcast storm has occurred on the virtual switch. 2. Check network connectivity (for example, check optical fiber or network cable connection, or check the optical power of the optical fiber), and verify that no loops exist on the network. 3. Identify whether the VM has a port profile or virtual firewall configured.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (83,30,2,82,'Number of sent packets dropped by a VM exceeded the threshold. Possible causes: 1. The outbound network port of the VM has a connection error. 2. Traffic sent by the Ethernet port of the VM exceeded the threshold. 3. Some applications on the VM consume the NIC traffic. 4. The VM has a port profile or virtual firewall configured.','1. Verify that no broadcast storm has occurred on the virtual switch. 2. Check network connectivity (for example, check optical fiber or network cable connection, or check the optical power of the optical fiber), and verify that no loops exist on the network. 3. Identify whether the VM has a port profile or virtual firewall configured.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (84,20,4,83,'Host MCE Alarm. Possible causes: 1. Memory, IO, or CPU fault.','1. Please check the file in /var/log/mcelog or check syslog messages to locate the hardware fault and remove it.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (85,30,4,79,'The shared file system was damaged. Possible causes: 1. The shared file system has damaged files.','1. If the auto repair result is SUCCESS, the damaged files were repaired successfully. In other cases, check for damaged files and repair them.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (87,30,4,85,'VM hot upgrade failure','1.Migrate, start, shut down, power off, or restart the VM.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (92,51,4,91,'Abnormal management platform HA quorum host. Possible causes: 1. The quorum host is abnormal. 2. Network of the quorum host is abnormal.','1. Verify that the quorum host is operating correctly. 2. Locate the causes of network failure.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (94,20,6,93,'Abnormal host process. Please verify that the process is needed.','1. Check for new software. 2. Verify that the host is not infected. 3. Identify whether this is a false alarm.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (95,20,6,94,'Shared file system management network error. Possible causes: 1. Physical link error. 2. IP configuration error.','Verify that the physical link is operating correctly and no duplicated IP addresses exist.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (109,20,4,108,'Failed to execute the fence umount command on the shared file system. Possible causes: 1. The storage device is abnormal. 2. The link between the physical host and the storage device is unstable or interrupted.','1. Verify that the link between the physical host and the storage device is running correctly. You can check the link quality through CRC error packets and optical power information about the adjacent switch. 2. View alarms and logs of the storage device to verify that the storage device is running correctly.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (110,30,4,109,'The VM is a ghost VM. Possible causes: 1. The VM is in shutdown state but its qemu process still exists.','As a best practice, contact technical support.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (99,20,1, 98,'Incoming error packet rate alarm for the vSwitch of the host. Possible causes: 1. Insufficient system memory. 2. Special packet formats or overlength packets.' ,'1. Check for excessive memory usage. 2. Check for packets in special formats or overlength packets.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (100,20,1, 99,'Incoming error packet rate alarm for the NIC of the host. Possible causes: 1. NIC ring buffer overflow. 2. Packet CRC error. 3. Frame alignment error.' ,'1. Check for excessive traffic or traffic bursts. 2. Check for carrier or cable faults. 3. Verify that the duplex mode and speed are consistent with the peer. 4. Verify that the NIC driver or firmware version matches the NIC.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (101,30,2, 100,'Incoming error packet rate alarm for the NIC of the VM. Possible causes: 1. NIC ring buffer overflow. 2. Packet CRC error. 3. Frame alignment error.' ,'1. Check for excessive traffic or traffic bursts. 2. Verify that the speed of the NIC is high. 3. Verify that the duplex mode and speed are consistent with the peer.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (102,20,1, 101,'Outgoing error packet rate alarm for the vSwitch of the host. Possible causes: 1. Insufficient system memory. 2. Special packet formats or overlength packets.' ,'1. Check for excessive memory usage. 2. Check for packets in special formats or overlength packets.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (103,20,1, 102,'Outgoing error packet rate alarm for the NIC of the host. Possible causes: 1. Carrier faults. 2. Abnormal transmission termination. 3. Queue errors.' ,'1. Check for excessive traffic or traffic bursts. 2. Check for carrier or cable faults. 3. Verify that the duplex mode and speed are consistent with the peer. 4. Verify that the NIC driver or firmware version matches the NIC.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (104,30,2, 103,'Outgoing error packet rate alarm for the NIC of the VM. Possible causes: 1. Carrier faults. 2. Abnormal transmission termination. 2. Queue errors.' ,'1. Check for excessive traffic or traffic bursts. 2. Verify that the speed of the NIC is high. 3. Verify that the duplex mode and speed are consistent with the peer. 4. Verify that the NIC driver or firmware version matches the NIC.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (105,20,4, 104,'Network link fault or abnormal storage access.', 'Check the network and storage.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (106,20,4, 105,'Storage access link failure.', 'Check the storage and storage access link.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (111,50,6, 110,'The Tomcat connection ratio has exceeded the limit. Possible cause: The total number of Tomcat connections to the system has exceeded the limit.' ,'1. Contact H3C Support.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (112,50,6, 111,'The number of Tomcat connections for a client has exceeded the limit. Possible cause: The number of Tomcat connections that a client has established to the system has exceeded the limit. This issue affects system stability.', '1. Locate the client based on the IP address in the alarm, and then reduce the number of connections that the client can establish to the system. 2. Contact H3C Support.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (113,30,6, 112,'A VM disk is in delete state. Possible causes: Manual misoperations at the backend or virus software.', '1. Do not shut down the VM. Please contact Technical Support to recover files on the disk.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (117,80,80, -1,'Possible causes: 1. Insufficient resources on the cluster nodes. 2. Insufficient container resources. 3. Incorrect workload, service, or storage configuration.','1. Add nodes or configure an expansion policy. 2. Edit container resource configuration. 3. Identify whether workloads and services are operating correctly, and check events and log messages to locate faults (if any).');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (118,30,2, 116,'The number of concurrent connections on the VM exceeded the upper limit. Possible causes: 1. A large number of concurrent connections are available on the VM. 2. The VM is under DDoS attacks.' ,'1. Capture packets to identify whether the VM is under DDoS attacks. 2. Identify whether the VM is providing a service that has a large number of concurrent connections.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (124,50,6, 118,'Possible reasons: 1. Destination email address error. 2. Alarm server configuration error. 3. Denied by the email server because of too many email server login failures.' ,'1. Verify that the destination email address and alarm server configuration are correct. 2. Add the CVM IP address to the email server allowlist.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (119,20,4, 120, 'Data disk removal alarm. Possible cause: A host data disk was removed.' , '1. Verify that the data disk removal operation is planned, hardware replacement for example. 2. If the data disk removal operation is unexpected, replace or insert the data disk as soon as possible.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (120,20,4, 121, 'Data disk insertion alarm. Possible cause: A host data disk was inserted.' , 'No action is required.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (121,20,4, 122, 'System disk removal alarm. Possible cause: A host system disk was removed.' , '1. Verify that the disk removal operation is planned, hardware replacement for example. 2. If the disk removal operation is unexpected, replace or insert the related disk in the system disk group as soon as possible.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (122,20,4, 123, 'System disk insertion alarm. Possible cause: A host system disk was inserted.' , 'No action is required.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (123,50,6, 117, 'Possible causes: 1. Invalid phone number for receiving short messages. 2. Incorrect short message configuration. 3. Too many SMS platform or server login failures. The request was rejected by the server.' ,'1. Verify the configuration of the phone number and short messages.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (125,30,4, 125, 'VM failure. Possible causes: 1. Shared storage network on the host has failed. 2. Shared storage exception on the host.','1. Troubleshoot link failure on the shared storage network. 2. Troubleshoot shared storage server failure.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (129,30,4, 129, 'VM fault. Possible cause: 1. The tools component is not installed on the VM. 2. The tools component is not running on the VM.', '1. Install the tools component on the VM and run the component.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (130,51,6, 130, 'Link anomaly alarm between CVM and the license server. Possible causes: The link between CVM and the license server is abnormal.', 'Check the link between CVM and the license server.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (131,30,7, 131, 'A program inside a VM calls a system call function on the attached host.','Identify whether the VM is infected with a virus or under attack, and remove the virus or terminate the attack.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (132,20,6, 132, 'A host process keeps in D state for a long time because it has been waiting for a response from resources. Possible causes: 1. Hardware failure. 2. Storage network anomaly. 3. Insufficient system resources.','Troubleshoot and repair hardware, driver, or storage network faults.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (133,20,1, 133, 'Host reserved hugePages memory utilization has exceeded the threshold. Possible causes: Too many VMs that use reserved HugePages are running.','1. Increase the number of reserved HugePages. 2. Manually migrate VMs that use reserved HugePages to other hosts.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (134,40,3, 134, 'Cluster reserved hugePages memory utilization has exceeded the threshold. Possible causes: Too many VMs that use reserved HugePages are running.','1. Check for hosts with high HugePages usage.2. Manually migrate VMs that use reserved HugePages to other clusters.');
INSERT INTO TBL_EVENT_CATALOG(ID, EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (136, 50, 6, 136, 'Possible causes: 1. CVM has a large number of connections. 2. Many tasks are running on CVM.', '1. Restrict the number of tasks deployed to CVM in a short period of time.');
INSERT INTO TBL_EVENT_CATALOG(ID, EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (137, 50, 6, 137, 'Possible causes: 1. Many tasks are running on CVM. 2. Other platforms are retrieving large amounts of data from CVM.', '1. Restrict the number of tasks deployed to CVM in a short period of time.2. Lower the frequency at which other platforms retrieve data from CVM.');
INSERT INTO TBL_EVENT_CATALOG(ID, EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (138, 50, 6, 138, 'Possible causes: 1. Many VM creation, deployment, and clone tasks are running on CVM.', '1. Restrict the number of VM creation, deployment, and clone tasks deployed to CVM in a short period of time.');
INSERT INTO TBL_EVENT_CATALOG(ID, EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (139, 50, 6, 139, 'Possible causes: 1. Many VM creation, deployment, and clone tasks are running on CVM.', '1. Restrict the number of VM creation, deployment, and clone tasks deployed to CVM in a short period of time.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6050,90,90, 6050,'Anti-malware alarm. Possible causes: Malware was detected on a VM.','1. Access the QAX unified server security management system and check the anti-malware log for details. 2. Deal with the malware based on its type. 3. Contact QAX Technical Support for malware sample inspection.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6051,90,90, 6051,'Intrusion prevention alarm. Possible causes:  Network intrusion was detected on a VM.','1. Access the QAX unified server security management system and check the intrusion prevention log for details. 2. Add firewall policies based on the intrusion prevention type. 3. Contact QAX Technical Support to report the intrusion prevention log.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6056,90,90, 6056,'Impending license expiration alarm. Possible causes: The product license is about to expire within 30 days.' ,'Access the QAX unified server security management system and update the license file.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6057,90,90, 6057,'Consecutive host synchronization failure alarm. Possible causes: Hosts and VMs on the hypervisor cannot be synchronized due to communication issues.' ,'1. Verify that the QAX unified server security management system has connectivity to the hypervisor. 2. Verify that the hypervisor is operating correctly. 3. Contact QAX Technical Support to troubleshoot the issue.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6058,90,90, 6058,'Abnormal cluster node service. Possible causes: A server is not operating correctly. ','1. Examine the status of the server. 2. Verify network connectivity between cluster nodes. 3. Contact QAX Technical Support to troubleshoot the issue.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6059,90,90, 6059,'Asynchronous system time between a host and the management center. Possible causes: The system time offset between a VM and the management center exceeded the allowed maximum value.' ,'Synchronize the system time of the VM with the QAX unified server security management system.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6060,90,90, 6060,'DDoS alarm. Possible causes: DDoS attacks were detected on a VM.' ,'1. Configure security policies accordingly on the firewall. 2. Fix the vulnerabilities of the operating system. 3. Contact QAX Technical Support to troubleshoot the issue.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6061,90,90, 6061,'Asynchronous system time between cluster nodes. Possible causes: The system time offset between cluster nodes exceeded the allowed maximum value.' ,'Synchronize the system time for the cluster nodes of the QAX unified server security management system.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6062,90,90, 6062,'Threat intelligence alarm. Possible causes: Asset risks were detected on a VM.' ,'1. Access the QAX unified server security management system and check the threat intelligence log for details. 2. View the threat processes and deal with them. 3. Contact QAX Technical Support to troubleshoot the issue.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6063,90,90, 6063,'High-risk vulnerability alarm. Possible causes: A high-risk vulnerability was detected on the VM.' ,'1. View the details in the vulnerability management system events on the QI-ANXIN Legendsec Unified Server Security Management System. 2. Manually fix the vulnerability based on the CVE number. 3. Enable virtual patching.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6064,90,90, 6064,'Integrity monitoring alarm. Possible causes: A monitored object change was detected on the VM.' ,'1. View the details in the integrity monitoring system events on the QI-ANXIN Legendsec Unified Server Security Management System. 2. Perform an anti-malware scanning. 3. Contact QI-ANXIN Technical Support.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6065,90,90, 6065,'Security baseline check alarm. Possible causes: Non-compliant items was detected in security baseline check on the VM.' ,'1. View the details in the security baseline system events on the QI-ANXIN Legendsec Unified Server Security Management System. 2. Modify the non-compliant items.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6066,90,90, 6066,'Webshell scanning alarm. Possible causes: A Webshell attack was detected on the VM.' ,'1. View the details in the Webshell system events on the QI-ANXIN Legendsec Unified Server Security Management System. 2. Select a repair method based on the backdoor type. 3. Contact QAX Technical Support to provide backdoor samples for detection.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6067,90,90, 6067,'Anti-violence cracking alarm. Possible causes: A violence cracking attack was detected on the VM.' ,'1. View the details in the anti-violence cracking system events on the QI-ANXIN Legendsec Unified Server Security Management System. 2. Add firewall policies as needed.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6068,90,90, 6068,'Weak system password alarm. Possible causes: A weak system password was detected on the VM.' ,'Use a password that meets the complexity requirements.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6069,90,90, 6069,'Insufficient space in the isolation zone. Possible causes: The available space in the malware isolation zone of the VM/endpoint is less than 15%.',' 1. Delete unnecessary malware in the isolation zone. 2. Expand the available space in the isolation zone.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6070,90,90, 6070,'Backup configuration failed. Possible causes: System backup configuration failed.',' 1. Perform the backup again. 2. Identify whether the disk space is less than 200M. 3. Contact QAX Technical Support to locate the issue.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8001,70,20, -1,'Storage cluster health alarm. Possible causes: 1. Storage cluster monitor failed. 2. Storage cluster OSD failed. 3. Storage cluster MDS failed.','1. Restart the storage cluster.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8002,70,20, -1,'Storage cluster pool health alarm. Possible causes: 1. Storage pool PG failed.','1. Manually repair PG. 2. Restart the storage cluster.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8003,70,20, -1,'Storage cluster volume health alarm. Possible causes: 1. Storage volume PG failed.','1. Manually repair PG. 2. Restart the storage cluster.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8004,70,20, -1,'Storage cluster monitor health alarm. Possible causes: 1. The system space usage of the failed node is too high. 2. The storage cluster has network faults. 3. Monitor process failure.','1. Clear the system space to reduce the system partition usage. 2. Restart the storage cluster monitor process.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8005,70,20, -1,'Storage cluster OSD health alarm. Possible causes: 1. The storage cluster load is too heavy. 2. The storage cluster has network faults.','1. Remove the OSD from the storage cluster and add it to the cluster again. 2. Restart the storage cluster OSD process.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8006,70,20, -1,'Storage cluster OSD usage alarm. Possible causes: 1. OSD size is too small. 2. The storage cluster is performing heavy write operations.' ,'1. Add more OSDs. 2. Reduce the load of the storage cluster.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8007,70,20, -1,'Storage cluster MDS health alarm. Possible causes: 1. The metadata of the file system for the storage cluster was corrupted.' ,'1. Restart the storage cluster MDS process.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8008,70,20, -1,'Storage cluster CPU usage alarm. Possible causes: 1. Too many processes are running in the cluster. 2. The storage cluster is performing heavy processing.' ,'1. Shut down some CPU-intensive processes. 2. Stop the services that require heavy processing. 3. Increase CPU resources for the storage cluster.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8009,70,20, -1,'Storage cluster memory usage alarm. Possible causes: 1. Too many processes are running in the cluster. 2. The storage cluster is performing heavy processing.' ,'1. Shut down some memory-intensive processes. 2. Stop the services that require heavy processing. 3. Increase memory resources for the storage cluster.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8010,70,20, -1,'Storage cluster capacity (hard disk usage) alarm. Possible reasons: 1. The hard disk size of the storage cluster is too small. 2. Too many files are saved in the hard disk of the storage cluster.' ,'1. Increase the partition capacity. 2. Delete useless files and uninstall useless programs.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8011,70,20, -1,'Storage cluster management network alarm. Possible causes: 1. Network link failed. 2. The NIC of the node to which the management network belongs failed.' ,'1. Check the network link. 2. Check the NIC of the management network.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8012,70,20, -1,'Storage cluster service network alarm. Possible causes: 1. Network link failed. 2. The NIC of the node to which the service network belongs failed.' ,'1. Check the network link. 2. Check the NIC of the service network.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8013,70,20, -1,'Storage cluster storage network alarm. Possible causes: 1. Network link failed. 2. The NIC of the node to which the storage network belongs failed.' ,'1. Check the network link. 2. Check the NIC of the storage network.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8014,70,20, -1,'Storage node CPU usage alarm. Possible causes: 1. Too many processes are running on the node. 2. The node is performing heavy processing.' ,'1. Shut down some CPU-intensive processes. 2. Stop the services that require heavy processing. 3. Increase CPU resources for the storage node.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8015,70,20, -1,'Storage node CPU temperature alarm. Possible causes: 1. Fan faults exist. 2. The CPU has operated with full load for a long time. 3. The environment temperature of the CPU is high.' ,'1. Check whether the fan operates correctly. 2. Check the CPU usage and shut down CPU-intensive processes. 3. Reduce the environment temperature for the CPU.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8016,70,20, -1,'Storage node memory usage alarm. Possible causes: 1. Too many processes are running on the node. 2. The node is performing heavy processing.' ,'1. Shut down some memory-intensive processes. 2. Stop the services that require heavy processing. 3. Increase memory resources for the storage node.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8017,70,20, -1,'Storage node capacity (hard disk usage) alarm. Possible reasons: 1. The hard disk size of the node is too small. 2. Too many files are saved in the hard disk of the node.' ,'1. Add more hard disks. 2. Delete useless files and uninstall useless programs.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8018,70,20, -1,'Storage node hard disk temperature alarm. Possible causes: 1. The IOPS value of the storage cluster is high and the hard disk is performing heavy read/write operations. 2. The environment temperature of the hard disk is high.' ,'1. Reduce read/write operations of the hard disk. 2. Reduce the environment temperature of the hard disk.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8019,70,20, -1,'Storage node hard disk partition (partition usage) alarm. Possible causes: 1. The partition size is too small. 2. Too many files are saved in the partition.' ,'1. Increase the partition capacity. 2. Delete useless files and uninstall useless programs.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (8020,70,20, -1,'Storage node network clock skew alarm. Possible causes: 1. Network clock source error. 2. Storage nodes configured with network clock synchronization are abnormal. 3. Storage nodes in the storage cluster cannot communicate correctly.' ,'1. Verify that the network clock source is correct. 2. Verify that storage nodes configured with network clock synchronization are correct. 3. Verify that storage nodes in the storage cluster can communicate correctly.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (115,20,6, 114,'An expiring password alarm was generated for the host. Possible cause: The password of the host is about to expire.', '1. Change the password of the host.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (116,20,6, 115,'An expired password alarm was generated for the host. Possible cause: The password of the host has expired.', '1. Change the password of the host.') ;
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6002,50,6, 6002,'The backup task is abnormal. Possible reasons: 1. The client process dies; 2. Network failure.', '1. Restart the client process; 2. Check for network link failure.');
INSERT INTO TBL_EVENT_CATALOG (ID,EVENT_TYPE, CATEGORY, RULE_ID, REASON, SUGGEST) VALUES (6001,50,6, 6001,'The backup service is abnormal. Possible reasons: 1. The service process is dead; 2. The media storage space is full.' ,'1. Restart the service process; 2. Clean up old storage space.');
